/** Target SP for an auto-built sub-group. Within a chapter, the (newest-first)
 *  releases are bucketed into ~30-SP sub-groups. */
const SUBGROUP_TARGET_SP = 30;

/** Summed story points of a node's leaves (a leaf returns its own sp). */
function leafSp(r: Release): number {
  return r.children?.length ? r.children.reduce((s, c) => s + leafSp(c), 0) : r.sp;
}

/** Greedily bucket an ordered list so each bucket's summed SP reaches ~target.
 *  A look-ahead closes a bucket early when the next item would overshoot badly,
 *  and a small trailing remainder is merged back into the previous bucket. */
function bucketBySp(items: Release[], target: number): Release[][] {
  const buckets: Release[][] = [];
  let cur: Release[] = [];
  let curSp = 0;
  for (const it of items) {
    const s = leafSp(it);
    if (cur.length && curSp >= target * 0.6 && curSp + s > target * 1.25) {
      buckets.push(cur); cur = []; curSp = 0;
    }
    cur.push(it);
    curSp += s;
    if (curSp >= target) { buckets.push(cur); cur = []; curSp = 0; }
  }
  if (cur.length) {
    if (buckets.length && curSp < target * 0.5) buckets[buckets.length - 1]!.push(...cur);
    else buckets.push(cur);
  }
  return buckets;
}

/** Newest / oldest leaf version under a node. */
function newestLeafVersion(r: Release): string {
  let n = r;
  while (n.children?.length) n = n.children[0]!;
  return n.version;
}
function oldestLeafVersion(r: Release): string {
  let n = r;
  while (n.children?.length) n = n.children[n.children.length - 1]!;
  return n.version;
}

/** Version span label "oldest-newest" for a newest-first list of nodes. */
function spanLabel(nodes: Release[]): string {
  const newest = newestLeafVersion(nodes[0]!);
  const oldest = oldestLeafVersion(nodes[nodes.length - 1]!);
  return oldest === newest ? newest : `${oldest}–${newest}`;
}

/** Descriptive, auto-chosen headline for a bucket: the title of its biggest leaf. */
function headlineTitle(nodes: Release[]): string {
  let best: Release | null = null;
  const walk = (r: Release) => {
    if (r.children?.length) r.children.forEach(walk);
    else if (!best || r.sp > best.sp) best = r;
  };
  nodes.forEach(walk);
  return best ? (best as Release).title : "Releases";
}

/** Which named chapter a version belongs to (the b.2.x minor, or a b.1 / 0.x era). */
function chapterKey(version: string): string {
  const m2 = version.match(/^b\.2\.(\d+)/);
  if (m2) return `b.2.${m2[1]}`;
  const m1 = version.match(/^b\.1\.(\d+)/);
  if (m1) return Number(m1[1]) >= 10 ? "b.1.hi" : "b.1.lo";
  return "0.x";
}

/** Descriptive chapter titles (the version "eras"). Unmapped chapters fall back
 *  to their biggest release's title, so new minors still read well. */
const CHAPTER_TITLES: Record<string, string> = {
  "b.2.6": "Version 2.6 milestone",
  "b.2.5": "Pose models & difficulty multipliers",
  "b.2.4": "Handstand modelling & analysis polish",
  "b.2.3": "Unified Analysis & timeline heatmap",
  "b.2.2": "Universal graph & exercise taxonomy",
  "b.2.1": "Fades, roles & per-set editing",
  "b.2.0": "Current strength & combined lifts",
  "b.1.hi": "Charts engine & live data",
  "b.1.lo": "Bottom nav, Add & compare",
  "0.x": "Before the reset",
};

/** Build the history tree from the flat, newest-first RELEASES list: one named
 *  chapter per version era (newest first), each auto-split into ~30-SP sub-groups
 *  (a small chapter keeps its releases directly). All SP totals roll up the tree. */
export function buildChangelogTree(releases: Release[]): Release[] {
  const order: string[] = [];
  const byChapter = new Map<string, Release[]>();
  for (const r of releases) {
    const k = chapterKey(r.version);
    if (!byChapter.has(k)) { byChapter.set(k, []); order.push(k); }
    byChapter.get(k)!.push(r);
  }
  return order.map((k) => {
    const rels = byChapter.get(k)!;
    const chrono = [...rels].reverse();
    const subgroups: Release[] = bucketBySp(chrono, SUBGROUP_TARGET_SP).map((leaves) => {
      const kids = [...leaves].reverse();
      return { version: spanLabel(kids), title: headlineTitle(kids), sp: 0,
        note: `${kids.length} releases.`, children: kids };
    });
    // bucketBySp walked chrono (oldest-first), so subgroups come out oldest-first;
    // flip to newest-first so children[0] is the newest era (what CURRENT_VERSION
    // and the version-history UI both assume). rels is already newest-first.
    const children = subgroups.length > 1 ? subgroups.reverse() : rels;
    return { version: k, title: CHAPTER_TITLES[k] ?? headlineTitle(rels), sp: 0,
      note: `${rels.length} releases.`, children };
  });
}

export const CHANGELOG: Release[] = [SOON, ...buildChangelogTree(RELEASES)];

// SP rolls UP the tree: a node with children is the (rounded) sum of its
// children, computed here so the totals can never drift from the leaf numbers.
// Rounded to one decimal so fractional SP (0.1, 0.5) can't show a binary
// floating-point tail like 90.30000000000001.
function rollupSp(r: Release): number {
  if (r.children?.length) {
    r.sp = Math.round(r.children.reduce((s, c) => s + rollupSp(c), 0) * 10) / 10;
  }
  return r.sp;
}
for (const r of CHANGELOG) rollupSp(r);

/** Count the leaf releases (the actual shipped versions) under a node. */
export function countReleases(r: Release): number {
  if (r.soon) return 0;
  if (!r.children?.length) return 1;
  return r.children.reduce((n, c) => n + countReleases(c), 0);
}

/**
 * TOTAL story points across the whole shipped log — summed from the top-level
 * groups (each already the rounded sum of everything beneath it), so it's
 * never hand-maintained and updates on its own when a release is added.
 */
export const TOTAL_LOG_SP = Math.round(
  CHANGELOG.filter((r) => !r.soon).reduce((sum, r) => sum + r.sp, 0) * 10,
) / 10;

/** The on-screen version: the newest actual leaf — descend the first child of
 * the newest shipped group until there are no more children. */
let newest = CHANGELOG.find((r) => !r.soon)!;
while (newest.children?.length) newest = newest.children[0]!;
export const CURRENT_VERSION = newest.version;

/** The modified-Fibonacci SP scale — the only allowed grades, no in-between. */
export const SP_SCALE = [1, 2, 3, 5, 8, 13, 20, 30, 50, 80, 130, 200] as const;

/** Snap an exact story-point count to the nearest value on {@link SP_SCALE}
 * (so a fib-SP is only ever 10, 20, 30, … never an in-between number). */
export function fibSp(n: number): number {
  let best = SP_SCALE[0] as number;
  for (const v of SP_SCALE) if (Math.abs(v - n) < Math.abs(best - n)) best = v;
  return best;
}

/**
 * Per-section EFFORT shown under the title — the EXACT story points spent on each
 * part (estimated by reading the whole history). Each part also carries a
 * Fibonacci grade ({@link fibSp}) so it reads both precisely and on the scale.
 */
export interface Component {
  name: string;
  /** Exact story points spent on this part. */
  sp: number;
}
export const COMPONENTS: Component[] = [
  { name: "Exercises", sp: 130 }, // drill-ins, categories, tiers, merges, rep-max header, best-sets, compare+sets, Index info + inspector + browse groups, active-exercises filter, combinable/comparable lifts, variation-difficulty model + 3-D pose editor
  { name: "Graphs", sp: 80 }, // SVG engine; real time axis + calendar bands, dashed reps, current strength, scatter, legend toggles, merged drill-in graph, sets/week bars, log trend
  { name: "Workouts", sp: 30 }, // day/week list, muscle-group view, rest days, year heatmap + day numbers + alone-tags, sets-over-time, RIR difficulty
  { name: "Athlete", sp: 22 }, // per-athlete pages, sticky chips, muscle map, momentum, training mix, four-tab view
  { name: "Data", sp: 20 }, // raw+processed CSV tab, every computed variable, search, live refresh from StrengthLevel + status
  { name: "Leaderboard", sp: 13 }, // boards, rank/sex/BW/axis filters, combined lifts in the picker
  { name: "Calculator", sp: 13 }, // multi-row reps↔weight calc + the Nuzzo research scatter/best-fit chart (shared with the explainer page), bar-weight axis
  { name: "Navigation", sp: 13 }, // bottom nav + Other sheet, Site map, version history (nested chapters) + SP-over-time
  { name: "Group", sp: 9 }, // train people together: combined comparison table, remembered picks
  { name: "Add", sp: 7 }, // hand-log sets, merge, export/import
  { name: "Stats", sp: 6 }, // per-category cards (was Groups)
];

/** Whole-site EXACT story points (sum of every part) and its Fibonacci grade. */
export const WEBSITE_EXACT_SP = COMPONENTS.reduce((s, c) => s + c.sp, 0);
export const WEBSITE_SP = fibSp(WEBSITE_EXACT_SP);

export interface SpTimelinePoint {
  version: string;
  sp: number;
  cumulative: number;
}

/** Walk the CHANGELOG tree oldest-first, collect every shipped leaf release, and
 *  return a cumulative SP timeline. Updates automatically when a release is added
 *  -- no external script needed. */
export function buildSpTimeline(): SpTimelinePoint[] {
  const leaves: { version: string; sp: number }[] = [];
  function collect(r: Release) {
    if (r.soon) return;
    if (!r.children?.length) {
      leaves.push({ version: r.version, sp: r.sp });
    } else {
      for (let i = r.children.length - 1; i >= 0; i--) collect(r.children[i]!);
    }
  }
  for (let i = CHANGELOG.length - 1; i >= 0; i--) collect(CHANGELOG[i]!);
  let cum = 0;
  return leaves.map((l) => {
    cum = Math.round((cum + l.sp) * 10) / 10;
    return { version: l.version, sp: l.sp, cumulative: cum };
  });
}
